          reviews: [{user:"RacingFan_123",avatar:"R",rating:5,date:"Feb 2025",text:"Best racing game in years! The physics are incredibly realistic and car variety is outstanding. Pure adrenaline!"},{user:"CasualClicks",avatar:"C",rating:4,date:"Feb 2025",text:"Perfect for weekend gaming sessions. Easy to pick up and play. The multiplayer mode adds tons of replay value."},{user:"PuzzleMaster_88",avatar:"P",rating:4,date:"Apr 2025",text:"Genuinely challenging puzzles that make you think. Great sense of accomplishment when you crack each one."},{user:"ShadowHunter_Z",avatar:"S",rating:5,date:"Mar 2025",text:"A masterpiece from start to finish. The attention to detail in every level is remarkable. My game of the year without question."},{user:"ActionHero_X",avatar:"A",rating:5,date:"Jan 2025",text:"This is the pinnacle of the genre. Everything from combat to story is polished to perfection. Buy it immediately!"}]
