          screenshots: ["assets/new-notable/DRAGON_QUEST_I_and_II_HD-2D_Remake/screenshots/s1.jpg", "assets/new-notable/DRAGON_QUEST_I_and_II_HD-2D_Remake/screenshots/s2.jpg", "assets/new-notable/DRAGON_QUEST_I_and_II_HD-2D_Remake/screenshots/s3.jpg", "assets/new-notable/DRAGON_QUEST_I_and_II_HD-2D_Remake/screenshots/s4.jpg"],
