          thumb: "assets/new-notable/Ghost_Shooting_Shooter_Games/thumb.jpg",
          screenshots: ["assets/new-notable/Ghost_Shooting_Shooter_Games/screenshots/s1.jpg", "assets/new-notable/Ghost_Shooting_Shooter_Games/screenshots/s2.jpg", "assets/new-notable/Ghost_Shooting_Shooter_Games/screenshots/s3.jpg", "assets/new-notable/Ghost_Shooting_Shooter_Games/screenshots/s4.jpg", "assets/new-notable/Ghost_Shooting_Shooter_Games/screenshots/s5.jpg", "assets/new-notable/Ghost_Shooting_Shooter_Games/screenshots/s6.jpg"],
